<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Ubuntu-like Desktop Environment</title>
    <style>
        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen, Ubuntu, Cantarell, "Open Sans", "Helvetica Neue", sans-serif;
        }

        body {
            overflow: hidden;
            height: 100vh;
            width: 100vw;
            background-color: #2e3440;
            color: #d8dee9;
        }

        /* Desktop */
        #desktop {
            position: relative;
            width: 100%;
            height: calc(100% - 40px);
            background: linear-gradient(135deg, #2e3440 0%, #3b4252 100%);
            overflow: hidden;
        }

        /* Taskbar */
        #taskbar {
            position: absolute;
            bottom: 0;
            left: 0;
            right: 0;
            height: 40px;
            background-color: rgba(30, 35, 42, 0.9);
            backdrop-filter: blur(10px);
            display: flex;
            align-items: center;
            padding: 0 10px;
            z-index: 1000;
            border-top: 1px solid #4c566a;
        }

        .launcher {
            width: 32px;
            height: 32px;
            margin-right: 10px;
            border-radius: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
            transition: background-color 0.2s, transform 0.1s;
        }

        .launcher:hover {
            background-color: rgba(76, 86, 106, 0.5);
        }

        .launcher:active {
            transform: scale(0.95);
        }

        .launcher-icon {
            width: 24px;
            height: 24px;
            fill: #d8dee9;
        }

        /* Windows */
        .window {
            position: absolute;
            background-color: #3b4252;
            border-radius: 10px;
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.5);
            overflow: hidden;
            display: none;
            min-width: 360px;
            min-height: 240px;
            border: 1px solid #4c566a;
        }

        .window.active {
            display: flex;
            flex-direction: column;
        }

        /* Window Header */
        .win-header {
            height: 32px;
            background-color: #4c566a;
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0 10px;
            cursor: default;
            user-select: none;
        }

        .win-title {
            font-size: 14px;
            color: #d8dee9;
        }

        .win-controls {
            display: flex;
            gap: 5px;
        }

        .win-close {
            width: 12px;
            height: 12px;
            border-radius: 50%;
            background-color: #bf616a;
            cursor: pointer;
            transition: transform 0.1s;
        }

        .win-close:hover {
            transform: scale(1.1);
        }

        /* Files Window */
        #files-window {
            top: 80px;
            left: 120px;
            width: 500px;
            height: 400px;
        }

        .files-container {
            display: flex;
            flex-direction: column;
            height: 100%;
        }

        .files-path-bar {
            padding: 8px 12px;
            background-color: #4c566a;
            border-bottom: 1px solid #3b4252;
            display: flex;
            align-items: center;
        }

        .path-text {
            font-size: 14px;
            color: #d8dee9;
        }

        .files-up-btn {
            margin-left: auto;
            padding: 4px 8px;
            background-color: #5e81ac;
            border-radius: 4px;
            cursor: pointer;
            font-size: 12px;
            color: white;
            transition: background-color 0.2s;
        }

        .files-up-btn:hover {
            background-color: #81a1c4;
        }

        .files-content {
            flex: 1;
            padding: 15px;
            overflow-y: auto;
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(80px, 1fr));
            gap: 15px;
            align-content: start;
        }

        .fs-item {
            display: flex;
            flex-direction: column;
            align-items: center;
            cursor: pointer;
            padding: 8px;
            border-radius: 4px;
            transition: background-color 0.2s;
            user-select: none;
        }

        .fs-item:hover {
            background-color: rgba(76, 86, 106, 0.5);
        }

        .fs-icon {
            width: 32px;
            height: 32px;
            margin-bottom: 4px;
            fill: #d8dee9;
        }

        .fs-name {
            font-size: 12px;
            text-align: center;
            word-break: break-word;
        }

        /* Notepad Window */
        #notepad-window {
            top: 60px;
            left: 540px;
            width: 600px;
            height: 450px;
        }

        .notepad-container {
            display: flex;
            flex-direction: column;
            height: 100%;
        }

        .tabs-bar {
            background-color: #4c566a;
            padding: 5px 10px 0;
            display: flex;
            gap: 2px;
            border-bottom: 1px solid #3b4252;
        }

        .tab {
            padding: 8px 16px;
            background-color: #3b4252;
            color: #d8dee9;
            border-radius: 6px 6px 0 0;
            cursor: pointer;
            font-size: 13px;
            transition: background-color 0.2s;
            display: flex;
            align-items: center;
            gap: 5px;
        }

        .tab.active {
            background-color: #4c566a;
            color: #d8dee9;
            font-weight: bold;
        }

        .tab:hover:not(.active) {
            background-color: rgba(76, 86, 106, 0.5);
        }

        .new-tab-btn {
            margin-left: auto;
            padding: 8px 12px;
            background-color: #4c566a;
            border-radius: 6px 6px 0 0;
            cursor: pointer;
            font-size: 13px;
            color: #d8dee9;
        }

        .new-tab-btn:hover {
            background-color: rgba(76, 86, 106, 0.5);
        }

        .editor-container {
            flex: 1;
            padding: 10px;
            overflow: hidden;
            display: flex;
            flex-direction: column;
        }

        #editor {
            flex: 1;
            background-color: #2e3440;
            color: #d8dee9;
            border: none;
            resize: none;
            padding: 10px;
            font-family: monospace;
            font-size: 14px;
            line-height: 1.5;
            outline: none;
        }

        /* Icons */
        .folder-icon {
            fill: #a3be8c;
        }

        .file-icon {
            fill: #d8dee9;
        }

        .home-icon {
            fill: #88c0d0;
        }

        .notepad-icon {
            fill: #b48ead;
        }
    </style>
</head>
<body>
    <div id="desktop">
        <!-- Taskbar -->
        <div id="taskbar">
            <div class="launcher" id="open-files" title="Files">
                <svg class="launcher-icon" viewBox="0 0 24 24">
                    <path d="M10 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/>
                </svg>
            </div>
            <div class="launcher" id="open-notepad" title="Notepad">
                <svg class="launcher-icon" viewBox="0 0 24 24">
                    <path d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-9V3.5L18.5 9H13z"/>
                </svg>
            </div>
        </div>

        <!-- Files Window -->
        <div id="files-window" class="window">
            <div class="win-header">
                <span class="win-title">Files</span>
                <div class="win-controls">
                    <div class="win-close"></div>
                </div>
            </div>
            <div class="files-container">
                <div class="files-path-bar">
                    <span id="files-path" class="path-text">/</span>
                    <button id="files-up" class="files-up-btn">↑ Up</button>
                </div>
                <div id="files-content" class="files-content"></div>
            </div>
        </div>

        <!-- Notepad Window -->
        <div id="notepad-window" class="window">
            <div class="win-header">
                <span class="win-title">Notepad</span>
                <div class="win-controls">
                    <div class="win-close"></div>
                </div>
            </div>
            <div class="notepad-container">
                <div id="tabs" class="tabs-bar">
                    <!-- Tabs will be added here -->
                </div>
                <div class="editor-container">
                    <textarea id="editor" placeholder="Type your notes here..."></textarea>
                </div>
            </div>
        </div>
    </div>

    <script>
        // File system data structure
        const fileSystem = {
            "bin": { type: "folder", children: {} },
            "etc": { type: "folder", children: {} },
            "home": { 
                type: "folder", 
                children: {
                    "user": {
                        type: "folder",
                        children: {
                            "Documents": { type: "folder", children: {} },
                            "Downloads": { type: "folder", children: {} },
                            "Pictures": { type: "folder", children: {} }
                        }
                    }
                }
            },
            "usr": { type: "folder", children: {} },
            "var": { type: "folder", children: {} }
        };

        // Files window state
        let currentPath = ["/"];

        // Notepad state
        let tabs = [];
        let activeTabId = null;
        const STORAGE_KEY = 'ubuntu_notepad_tabs';

        // DOM Elements
        const desktop = document.getElementById('desktop');
        const taskbar = document.getElementById('taskbar');
        const openFilesBtn = document.getElementById('open-files');
        const openNotepadBtn = document.getElementById('open-notepad');
        const filesWindow = document.getElementById('files-window');
        const notepadWindow = document.getElementById('notepad-window');
        const filesPathElement = document.getElementById('files-path');
        const filesContentElement = document.getElementById('files-content');
        const filesUpButton = document.getElementById('files-up');
        const tabsContainer = document.getElementById('tabs');
        const editor = document.getElementById('editor');

        // File system icon SVGs
        function getFolderIcon() {
            return `<svg class="fs-icon folder-icon" viewBox="0 0 24 24"><path d="M10 4H4c-1.1 0-1.99.9-1.99 2L2 18c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V8c0-1.1-.9-2-2-2h-8l-2-2z"/></svg>`;
        }

        function getFileIcon() {
            return `<svg class="fs-icon file-icon" viewBox="0 0 24 24"><path d="M14 2H6c-1.1 0-1.99.9-1.99 2L4 20c0 1.1.89 2 1.99 2H18c1.1 0 2-.9 2-2V8l-6-6zm2 16H8v-2h8v2zm0-4H8v-2h8v2zm-3-9V3.5L18.5 9H13z"/></svg>`;
        }

        // Files window functionality
        function renderFiles() {
            filesContentElement.innerHTML = '';

            // Get current directory object
            let currentDir = fileSystem;
            for (let i = 1; i < currentPath.length; i++) {
                const segment = currentPath[i];
                if (currentDir.children && currentDir.children[segment]) {
                    currentDir = currentDir.children[segment];
                } else {
                    break;
                }
            }

            // Show parent directory button if not at root
            if (currentPath.length > 1) {
                const upItem = document.createElement('div');
                upItem.className = 'fs-item';
                upItem.innerHTML = `
                    <svg class="fs-icon" viewBox="0 0 24 24">
                        <path d="M12 8L4 16h3v8h10v-8h3l-8-8z"/>
                    </svg>
                    <div class="fs-name">..</div>
                `;
                upItem.addEventListener('click', function() {
                    navigateUp();
                });
                filesContentElement.appendChild(upItem);
            }

            // Render items in current directory
            if (currentDir.children) {
                const sortedItems = Object.entries(currentDir.children).sort((a, b) => {
                    // Folders first, then alphabetically
                    if (a[1].type === 'folder' && b[1].type !== 'folder') return -1;
                    if (a[1].type !== 'folder' && b[1].type === 'folder') return 1;
                    return a[0].localeCompare(b[0]);
                });

                for (const [name, item] of sortedItems) {
                    const itemElement = document.createElement('div');
                    itemElement.className = 'fs-item';

                    if (item.type === 'folder') {
                        itemElement.innerHTML = `
                            ${getFolderIcon()}
                            <div class="fs-name">${name}</div>
                        `;
                        itemElement.addEventListener('dblclick', function() {
                            navigateTo([...currentPath, name]);
                        });
                    } else {
                        itemElement.innerHTML = `
                            ${getFileIcon()}
                            <div class="fs-name">${name}</div>
                        `;
                    }

                    filesContentElement.appendChild(itemElement);
                }
            }
        }

        function navigateTo(path) {
            currentPath = path;
            updateFilesPath();
            renderFiles();
        }

        function navigateUp() {
            if (currentPath.length > 1) {
                currentPath.pop();
                updateFilesPath();
                renderFiles();
            }
        }

        function updateFilesPath() {
            filesPathElement.textContent = currentPath.join('/');
        }

        // Notepad functionality
        function generateTabId() {
            return 'tab-' + Date.now().toString(36) + Math.random().toString(36).substr(2);
        }

        function createNewTab(content = '') {
            const tabId = generateTabId();
            tabs.push({ id: tabId, title: `Tab ${tabs.length + 1}`, content });

            if (activeTabId === null) {
                activeTabId = tabId;
            }

            renderTabs();
            saveTabsToStorage();
        }

        function renderTabs() {
            tabsContainer.innerHTML = '';

            // Render existing tabs
            for (const tab of tabs) {
                const tabElement = document.createElement('div');
                tabElement.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
                tabElement.textContent = tab.title;

                tabElement.addEventListener('click', function() {
                    activateTab(tab.id);
                });

                tabsContainer.appendChild(tabElement);
            }

            // Add new tab button
            const newTabBtn = document.createElement('div');
            newTabBtn.className = 'new-tab-btn';
            newTabBtn.textContent = '+ New Tab';
            newTabBtn.addEventListener('click', function() {
                createNewTab();
            });
            tabsContainer.appendChild(newTabBtn);

            // Update editor content
            if (activeTabId) {
                const activeTab = tabs.find(tab => tab.id === activeTabId);
                if (activeTab) {
                    editor.value = activeTab.content;
                }
            } else {
                editor.value = '';
            }
        }

        function activateTab(tabId) {
            activeTabId = tabId;

            // Update UI
            renderTabs();

            // Save current content before switching
            if (activeTabId && tabs.length > 0) {
                const activeTab = tabs.find(tab => tab.id === activeTabId);
                if (activeTab) {
                    editor.value = activeTab.content;
                }
            }
        }

        function saveCurrentTabContent() {
            if (activeTabId) {
                const activeTab = tabs.find(tab => tab.id === activeTabId);
                if (activeTab) {
                    activeTab.content = editor.value;
                    saveTabsToStorage();
                }
            }
        }

        function saveTabsToStorage() {
            localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs));
            if (activeTabId) {
                const activeTab = tabs.find(tab => tab.id === activeTabId);
                if (activeTab) {
                    localStorage.setItem(`${STORAGE_KEY}_${activeTabId}`, activeTab.content);
                }
            }
        }

        function loadTabsFromStorage() {
            const savedTabs = localStorage.getItem(STORAGE_KEY);
            if (savedTabs) {
                try {
                    tabs = JSON.parse(savedTabs);

                    // Load content for each tab
                    for (const tab of tabs) {
                        const savedContent = localStorage.getItem(`${STORAGE_KEY}_${tab.id}`);
                        if (savedContent !== null) {
                            tab.content = savedContent;
                        }
                    }

                    if (tabs.length > 0) {
                        activeTabId = tabs[0].id;
                    } else {
                        createNewTab();
                    }
                } catch (e) {
                    console.error('Error loading tabs from storage:', e);
                    createNewTab();
                }
            } else {
                createNewTab();
            }
        }

        // Window management
        function openFilesWindow() {
            filesWindow.classList.add('active');

            // Bring to front by adjusting z-index
            const allWindows = document.querySelectorAll('.window');
            let maxZIndex = 100;
            allWindows.forEach(win => {
                if (parseInt(win.style.zIndex) > maxZIndex) {
                    maxZIndex = parseInt(win.style.zIndex);
                }
            });
            filesWindow.style.zIndex = maxZIndex + 1;

            // Focus on path
            updateFilesPath();
            renderFiles();
        }

        function openNotepadWindow() {
            notepadWindow.classList.add('active');

            // Bring to front by adjusting z-index
            const allWindows = document.querySelectorAll('.window');
            let maxZIndex = 100;
            allWindows.forEach(win => {
                if (parseInt(win.style.zIndex) > maxZIndex) {
                    maxZIndex = parseInt(win.style.zIndex);
                }
            });
            notepadWindow.style.zIndex = maxZIndex + 1;

            // Focus on editor
            renderTabs();
        }

        function closeWindow(windowElement) {
            windowElement.classList.remove('active');
        }

        // Event listeners for launcher buttons
        openFilesBtn.addEventListener('click', openFilesWindow);
        openNotepadBtn.addEventListener('click', openNotepadWindow);

        // Close button functionality
        filesWindow.querySelector('.win-close').addEventListener('click', function() {
            closeWindow(filesWindow);
        });

        notepadWindow.querySelector('.win-close').addEventListener('click', function() {
            closeWindow(notepadWindow);
        });

        // Files window up button
        filesUpButton.addEventListener('click', navigateUp);

        // Notepad editor content saving
        editor.addEventListener('input', saveCurrentTabContent);

        // Initialize
        document.addEventListener('DOMContentLoaded', function() {
            // Initialize notepad from storage
            loadTabsFromStorage();

            // Set initial path to root
            currentPath = ["/"];
            updateFilesPath();
            renderFiles();

            // Add click outside windows to close them (optional enhancement)
            desktop.addEventListener('click', function(e) {
                if (e.target === desktop) {
                    filesWindow.classList.remove('active');
                    notepadWindow.classList.remove('active');
                }
            });
        });

        // Prevent window dragging from interfering with other elements
        document.querySelectorAll('.win-header').forEach(header => {
            header.addEventListener('mousedown', function(e) {
                e.stopPropagation();
            });
        });
    </script>
</body>
</html>
